-- ============================================================
--  SOURCE DATABASE — FINAL TEST DATA  (v2 — finalised schema)
--  vehicle_manufacturing_src
--
--  New columns vs previous version:
--    suppliers      : created_at, updated_at, deleted_at
--    vehicles       : created_at, updated_at, deleted_at
--    parts          : created_at, deleted_at
--    quality_checks : created_at, deleted_at
--
--  Interesting data points baked in:
--    SUP016, SUP020       is_active = 0  (inactive suppliers)
--    SUP020               deleted_at set (soft-deleted supplier)
--    SUP003,007,012,018   updated_at set (rating/tier edited)
--    vehicles 15,42,87,133,178  deleted_at set (soft-deleted)
--    ~29 vehicles         updated_at set (status/score updated)
--    parts of vehicle 42  deleted_at set (recall scenario)
--    2 quality_checks     deleted_at set (data entry error)
-- ============================================================

USE vehicle_manufacturing_src;

SET FOREIGN_KEY_CHECKS = 0;
TRUNCATE TABLE quality_checks;
TRUNCATE TABLE parts;
TRUNCATE TABLE vehicles;
TRUNCATE TABLE suppliers;
SET FOREIGN_KEY_CHECKS = 1;

